 // Stop halts the file reservation watcher and releases all reservations.
 func (w *FileReservationWatcher) Stop() {
-	if w.cancelFunc != nil {
-		w.cancelFunc()
+	w.mu.Lock()
+	cancel := w.cancelFunc
+	w.mu.Unlock()
+
+	if cancel != nil {
+		cancel()
 	}
 	w.wg.Wait()

+	w.mu.Lock()
+	w.cancelFunc = nil
+	w.mu.Unlock()
+
 	// Release all reservations on stop
 	w.releaseAllReservations()
